def _clean_name(name: object) -> str:
    text = str(name).strip().replace("\n", " ")
    text = re.sub(r"\s+", " ", text)
    return text


def _alias_key(name: str) -> str:
    return _clean_name(name).lower().replace("ё", "е")


def normalize_columns(df: pd.DataFrame) -> pd.DataFrame:
    """Rename Russian/English headings to the internal schema.

    The app still displays Russian labels in the interface; internal English names make
    filtering and map generation predictable.
    """
    df = df.copy()
    renamed: dict[str, str] = {}

    for col in df.columns:
        clean = _clean_name(col)
        key = _alias_key(clean)

        unit_match = re.match(
            r"^(лингвистическая\s+единица|единица|ответ|variant|unit|linguistic_unit)[ _-]*(\d+)$",
            key,
        )
        if unit_match:
            renamed[col] = f"linguistic_unit_{unit_match.group(2)}"
            continue

        if key in ALIASES:
            renamed[col] = ALIASES[key]
        else:
            renamed[col] = clean

    return df.rename(columns=renamed)


def ensure_columns(df: pd.DataFrame) -> pd.DataFrame:
    df = normalize_columns(df)

    for col in CANONICAL_COLUMNS:
        if col not in df.columns:
            df[col] = ""

    df["latitude"] = pd.to_numeric(df["latitude"], errors="coerce")
    df["longitude"] = pd.to_numeric(df["longitude"], errors="coerce")

    for text_col in [
        "region",
        "district",
        "settlement",
        "settlement_type",
        "landscape",
        "atlas_system",
        "question_type",
        "question_id",
        "question",
        "comment",
        "source",
        "year",
    ]:
        df[text_col] = df[text_col].fillna("").astype(str).str.strip()

    for col in get_linguistic_columns(df):
        df[col] = df[col].fillna("").astype(str).str.strip()

    df["atlas_system"] = df["atlas_system"].replace({"": "не указан"})
    df["question_type"] = df["question_type"].replace({"": "не указан"})
    df["landscape"] = df["landscape"].replace({"": "не указан"})
    df["question_id"] = df.apply(
        lambda row: row["question_id"] or _make_question_id(row["atlas_system"], row["question"]),
        axis=1,
    )
    return df


def _make_question_id(atlas_system: str, question: str) -> str:
    prefix = "Q"
    if "ДАР" in atlas_system.upper():
        prefix = "D"
    elif "ЛАР" in atlas_system.upper():
        prefix = "L"
    digest = abs(hash(question)) % 10000
    return f"{prefix}-{digest:04d}"


def read_csv_bytes(content: bytes, sep: str | None = None) -> pd.DataFrame:
    """Read uploaded CSV bytes with tolerant UTF-8/CP1251 handling."""
    for encoding in ("utf-8-sig", "utf-8", "cp1251"):
        try:
            text = content.decode(encoding)
            return ensure_columns(pd.read_csv(StringIO(text), sep=sep or None, engine="python"))
        except Exception:
            continue
    raise ValueError("Не удалось прочитать CSV. Проверьте кодировку UTF-8/CP1251 и разделитель.")


def read_csv_path(path: str) -> pd.DataFrame:
    for encoding in ("utf-8-sig", "utf-8", "cp1251"):
        try:
            return ensure_columns(pd.read_csv(path, encoding=encoding))
        except Exception:
            continue
    raise ValueError(f"Не удалось прочитать файл: {path}")


def read_csv_url(url: str) -> pd.DataFrame:
    return ensure_columns(pd.read_csv(url))


def get_linguistic_columns(df: pd.DataFrame) -> list[str]:
    cols = []
    for col in df.columns:
        if re.match(r"^linguistic_unit_\d+$", str(col)):
            cols.append(col)
    return sorted(cols, key=lambda c: int(c.rsplit("_", 1)[1]))


def split_units(value: object) -> list[str]:
    if value is None or pd.isna(value):
        return []
    parts = re.split(r";|,|\|", str(value))
    return [p.strip() for p in parts if p and p.strip()]


def row_units(row: pd.Series, unit_cols: Iterable[str] | None = None) -> list[str]:
    if unit_cols is None:
        unit_cols = [c for c in row.index if re.match(r"^linguistic_unit_\d+$", str(c))]
    units: list[str] = []
    for col in unit_cols:
        units.extend(split_units(row.get(col, "")))
    # Preserve order, remove duplicates.
    seen = set()
    result = []
    for unit in units:
        key = unit.lower()
        if key not in seen:
            seen.add(key)
            result.append(unit)
    return result


def add_unit_display(df: pd.DataFrame) -> pd.DataFrame:
    df = df.copy()
    unit_cols = get_linguistic_columns(df)
    df["unit_display"] = df.apply(lambda row: "; ".join(row_units(row, unit_cols)), axis=1)
    df["unit_display"] = df["unit_display"].replace({"": "нет данных"})
    return df


def explode_units(df: pd.DataFrame) -> pd.DataFrame:
    df = ensure_columns(df)
    unit_cols = get_linguistic_columns(df)
    records = []

    for _, row in df.iterrows():
        units = row_units(row, unit_cols)
        if not units:
            units = ["нет данных"]

        for unit in units:
            item = row.to_dict()
            item["linguistic_unit"] = unit
            records.append(item)

    return pd.DataFrame(records)


def get_all_units(df: pd.DataFrame) -> list[str]:
    units = set()
    for _, row in df.iterrows():
        for unit in row_units(row):
            if unit:
                units.add(unit)
    return sorted(units, key=lambda item: item.lower())


def question_catalog(df: pd.DataFrame) -> pd.DataFrame:
    df = add_unit_display(ensure_columns(df))
    grouped = (
        df.groupby(["question_id", "question", "atlas_system", "question_type"], dropna=False)
        .agg(
            records=("settlement", "size"),
            settlements=("settlement", "nunique"),
            regions=("region", "nunique"),
            districts=("district", "nunique"),
            units=("unit_display", lambda s: "; ".join(sorted({u for v in s for u in split_units(v)}))),
        )
        .reset_index()
        .sort_values(["atlas_system", "question_type", "question_id"])
    )
    return grouped


def filter_dataframe(
    df: pd.DataFrame,
    regions: list[str] | None = None,
    districts: list[str] | None = None,
    question: str | None = None,
    unit_query: str | None = None,
    text_query: str | None = None,
) -> pd.DataFrame:
    df = add_unit_display(ensure_columns(df))

    if regions:
        df = df[df["region"].isin(regions)]

    if districts:
        df = df[df["district"].isin(districts)]

    if question and question != "Все вопросы":
        df = df[(df["question"] == question) | (df["question_id"] == question)]

    if unit_query:
        query = unit_query.strip().lower()
        if query:
            df = df[df["unit_display"].str.lower().str.contains(re.escape(query), na=False)]

    if text_query:
        query = text_query.strip().lower()
        if query:
            haystack = (
                df["region"]
                + " "
                + df["district"]
                + " "
                + df["settlement"]
                + " "
                + df["question"]
                + " "
                + df["unit_display"]
                + " "
                + df["comment"]
            ).str.lower()
            df = df[haystack.str.contains(re.escape(query), na=False)]

    return df


def validate_dataframe(df: pd.DataFrame) -> list[dict[str, str]]:
    df = ensure_columns(df)
    issues: list[dict[str, str]] = []

    for col in REQUIRED_COLUMNS:
        empty_count = int((df[col].fillna("").astype(str).str.strip() == "").sum())
        if empty_count:
            issues.append(
                {
                    "level": "Ошибка",
                    "field": col,
                    "message": f"Пустых значений: {empty_count}",
                }
            )

    no_coords = int(df[["latitude", "longitude"]].isna().any(axis=1).sum())
    if no_coords:
        issues.append(
            {
                "level": "Предупреждение",
                "field": "latitude/longitude",
                "message": f"Записей без координат: {no_coords}; они не появятся на карте.",
            }
        )

    invalid_question_types = sorted(
        {
            q
            for q in df["question_type"].dropna().unique()
            if q and q != "не указан" and q not in ALLOWED_QUESTION_TYPES
        }
    )
    if invalid_question_types:
        issues.append(
            {
                "level": "Предупреждение",
                "field": "question_type",
                "message": "Нетиповые разделы: " + "; ".join(invalid_question_types),
            }
        )

    unit_cols = get_linguistic_columns(df)
    if not unit_cols:
        issues.append(
            {
                "level": "Ошибка",
                "field": "linguistic_unit_*",
                "message": "Добавьте хотя бы один столбец linguistic_unit_1 / «лингвистическая единица 1».",
            }
        )
    else:
        empty_units = int(df[unit_cols].replace("", pd.NA).isna().all(axis=1).sum())
        if empty_units:
            issues.append(
                {
                    "level": "Предупреждение",
                    "field": "linguistic_unit_*",
                    "message": f"Записей без лингвистических единиц: {empty_units}.",
                }
            )

    duplicate_rows = int(
        df.duplicated(subset=["region", "district", "settlement", "question_id", "question"]).sum()
    )
    if duplicate_rows:
        issues.append(
            {
                "level": "Предупреждение",
                "field": "duplicates",
                "message": f"Возможных дублей пункт-вопрос: {duplicate_rows}.",
            }
        )

    return issues


def to_download_csv(df: pd.DataFrame) -> bytes:
    return df.to_csv(index=False).encode("utf-8-sig")


# --- Встроенные функции из geo_utils.py: карта работает без отдельного импорта. ---
def label_color(label: object, alpha: int = 190) -> list[int]:
    """Stable readable color from any label."""
    text = str(label or "нет данных").encode("utf-8")
    digest = hashlib.md5(text).hexdigest()
    hue = int(digest[:6], 16) / 0xFFFFFF
    # Moderate saturation/lightness keeps text and map readable.
    r, g, b = colorsys.hls_to_rgb(hue, 0.50, 0.58)
    return [int(r * 255), int(g * 255), int(b * 255), alpha]


def label_color_hex(label: object) -> str:
    r, g, b, _ = label_color(label)
    return f"#{r:02x}{g:02x}{b:02x}"


def _cross(origin: tuple[float, float], a: tuple[float, float], b: tuple[float, float]) -> float:
    return (a[0] - origin[0]) * (b[1] - origin[1]) - (a[1] - origin[1]) * (b[0] - origin[0])


def convex_hull(points: Iterable[tuple[float, float]]) -> list[list[float]]:
    """Monotonic-chain hull for lon/lat points. Returns a closed polygon."""
    pts = sorted(set(points))
    if len(pts) < 3:
        return []

    lower: list[tuple[float, float]] = []
    for point in pts:
        while len(lower) >= 2 and _cross(lower[-2], lower[-1], point) <= 0:
            lower.pop()
        lower.append(point)

    upper: list[tuple[float, float]] = []
    for point in reversed(pts):
        while len(upper) >= 2 and _cross(upper[-2], upper[-1], point) <= 0:
            upper.pop()
        upper.append(point)

    hull = lower[:-1] + upper[:-1]
    if len(hull) < 3:
        return []

    closed = hull + [hull[0]]
    return [[float(lon), float(lat)] for lon, lat in closed]


def map_view_state(df: pd.DataFrame) -> dict[str, float]:
    valid = df.dropna(subset=["latitude", "longitude"])
    if valid.empty:
        return {"latitude": 57.1, "longitude": 53.2, "zoom": 6.5, "pitch": 0}

    lat_min, lat_max = valid["latitude"].min(), valid["latitude"].max()
    lon_min, lon_max = valid["longitude"].min(), valid["longitude"].max()
    lat_span = max(lat_max - lat_min, 0.2)
    lon_span = max(lon_max - lon_min, 0.2)
    span = max(lat_span, lon_span)

    if span > 5:
        zoom = 5.5
    elif span > 2.5:
        zoom = 6.2
    elif span > 1:
        zoom = 7.2
    else:
        zoom = 8.4

    return {
        "latitude": float((lat_min + lat_max) / 2),
        "longitude": float((lon_min + lon_max) / 2),
        "zoom": zoom,
        "pitch": 0,
    }


def build_areals(exploded_df: pd.DataFrame, group_col: str = "linguistic_unit") -> list[dict]:
    valid = exploded_df.dropna(subset=["latitude", "longitude"]).copy()
    if valid.empty or group_col not in valid.columns:
        return []

    areals: list[dict] = []
    for label, group in valid.groupby(group_col):
        points = list(zip(group["longitude"].astype(float), group["latitude"].astype(float)))
        polygon = convex_hull(points)
        if len(polygon) < 4:
            continue

        color = label_color(label, alpha=24)
        areals.append(
            {
                "label": str(label),
                "polygon": polygon,
                "path": polygon,
                "count": int(group["settlement"].nunique()),
                "fill_color": color,
                "line_color": [color[0], color[1], color[2], 145],
            }
        )

    return sorted(areals, key=lambda item: (-item["count"], item["label"]))


def add_point_visuals(points_df: pd.DataFrame, color_mode: str) -> pd.DataFrame:
    points_df = points_df.copy()

    if color_mode == "Ландшафт":
        points_df["color_label"] = points_df["landscape"].replace("", "не указан")
    elif color_mode == "Тип вопроса":
        points_df["color_label"] = points_df["question_type"].replace("", "не указан")
    elif color_mode == "Атлас":
        points_df["color_label"] = points_df["atlas_system"].replace("", "не указан")
    else:
        points_df["color_label"] = points_df["unit_display"].replace("", "нет данных")

    points_df["color"] = points_df["color_label"].apply(lambda value: label_color(value, alpha=210))
    points_df["outline_color"] = points_df["color_label"].apply(lambda value: label_color(value, alpha=255))
    points_df["radius_m"] = 6500 + points_df["record_count"].clip(0, 10).astype(int) * 700
    points_df["short_label"] = points_df["settlement"].str.slice(0, 18)
    return points_df


def aggregate_points(df: pd.DataFrame) -> pd.DataFrame:
    valid = df.dropna(subset=["latitude", "longitude"]).copy()
    if valid.empty:
        return pd.DataFrame()

    def unique_join(series: pd.Series, limit: int = 9) -> str:
        values: list[str] = []
        for value in series.dropna().astype(str):
            for item in value.split(";"):
                item = item.strip()
                if item and item not in values:
                    values.append(item)
        shown = values[:limit]
        suffix = "" if len(values) <= limit else f"; +{len(values) - limit}"
        return "; ".join(shown) + suffix

    grouped = (
        valid.groupby(["region", "district", "settlement", "latitude", "longitude"], dropna=False)
        .agg(
            settlement_type=("settlement_type", "first"),
            landscape=("landscape", "first"),
            atlas_system=("atlas_system", unique_join),
            question_type=("question_type", unique_join),
            question_label=("question", unique_join),
            unit_display=("unit_display", unique_join),
            comments=("comment", unique_join),
            record_count=("question", "size"),
            question_count=("question", "nunique"),
        )
        .reset_index()
    )

    grouped["tooltip"] = grouped.apply(
        lambda row: (
            f"<b>{row['settlement']}</b><br/>"
            f"{row['district']}, {row['region']}<br/>"
            f"<b>Ландшафт:</b> {row['landscape']}<br/>"
            f"<b>Вопросы:</b> {row['question_label']}<br/>"
            f"<b>Единицы:</b> {row['unit_display']}<br/>"
            f"<b>Комментарий:</b> {row['comments'] or '—'}"
        ),
        axis=1,
    )

    return grouped


