def load_sample_data() -> pd.DataFrame:
    """Load bundled demo data, with an embedded fallback for single-file deploys."""
    if SAMPLE_DATA_PATH.exists():
        return read_csv_path(str(SAMPLE_DATA_PATH))
    return read_csv_bytes(SAMPLE_DATA_CSV.encode("utf-8-sig"))


def read_template_bytes() -> bytes:
    """Return the CSV template, even if the data folder was not uploaded."""
    if TEMPLATE_DATA_PATH.exists():
        return TEMPLATE_DATA_PATH.read_bytes()
    return TEMPLATE_DATA_CSV.encode("utf-8-sig")


