def render_help_page() -> None:
    st.subheader("Инструкция пользователя")

    st.markdown(
        """
        ### Для зрителя
        Откройте вкладку **Атлас**, выберите регион, район, карту-вопрос или лингвистическую единицу.
        Точки показывают населённые пункты, цвет — выбранный режим легенды. При наведении видны вопрос,
        единицы, ландшафт и комментарий.

        ### Для редактора таблицы
        Заполняйте Google Sheets по шаблону: одна строка = один населённый пункт + один вопрос.
        Для нескольких ответов используйте столбцы `linguistic_unit_1`, `linguistic_unit_2`, `linguistic_unit_3`
        или разделяйте варианты точкой с запятой. После редактирования нажмите **Обновить кэш данных** в боковой панели.

        ### Для составителя карт
        Карта считается вопросом атласа. Чтобы добавить новую карту, внесите новый `question_id`, `question`,
        `atlas_system`, `question_type` и заполните ответы по пунктам. Во вкладке **Карты** появится паспорт карты,
        варианты единиц, автоматические ареалы и контурные изоглоссы.

        ### Типы вопросов
        Для ДАРЯ используйте разделы: `ДАРЯ: фонетика`, `ДАРЯ: морфология`, `ДАРЯ: синтаксис`, `ДАРЯ: лексика`.
        Для ЛАРНГ используйте тематические лексические разделы: природа, растительный мир, животный мир,
        человек, материальная культура, духовная культура, социальная сфера.

        ### Ограничения демонстрационной версии
        Авто-изоглоссы строятся по выпуклой оболочке точек. Это удобно для учебной демонстрации, но научные
        границы лучше рисовать и проверять в QGIS/ArcGIS/NextGIS, затем загружать как GeoJSON.
        """
    )

    st.markdown("### Допустимые значения `question_type`")
    st.dataframe(pd.DataFrame({"question_type": ALLOWED_QUESTION_TYPES}), hide_index=True, use_container_width=True)

    st.markdown("### Быстрый запуск")
    st.code(
        """pip install -r requirements.txt
streamlit run streamlit_app.py""",
        language="bash",
    )


def get_working_dataframe(df: pd.DataFrame) -> pd.DataFrame:
    """Return source data plus rows added during the current Streamlit session."""
    df = ensure_columns(df)
    added_records = st.session_state.get("added_records", [])
    if not added_records:
        return df

    added_df = ensure_columns(pd.DataFrame(added_records))
    combined = pd.concat([df, added_df], ignore_index=True, sort=False)
    return ensure_columns(combined)


def parse_float_input(value: str, field_name: str) -> float:
    text = str(value).strip().replace(",", ".")
    if not text:
        raise ValueError(f"Поле «{field_name}» обязательно.")
    try:
        return float(text)
    except ValueError as exc:
        raise ValueError(f"В поле «{field_name}» должно быть число.") from exc


def render_light_dataframe(df: pd.DataFrame, key: str, height: int = 420) -> None:
    """Draw a light table even when the browser or host prefers a dark theme."""
    display_df = df.copy()
    try:
        styled = (
            display_df.style
            .set_properties(**{
                "background-color": "#ffffff",
                "color": "#0f172a",
                "border-color": "#e2e8f0",
            })
            .set_table_styles(
                [
                    {
                        "selector": "thead th",
                        "props": [
                            ("background-color", "#f8fafc"),
                            ("color", "#0f172a"),
                            ("border-color", "#e2e8f0"),
                        ],
                    },
                    {
                        "selector": "tbody td",
                        "props": [
                            ("background-color", "#ffffff"),
                            ("color", "#0f172a"),
                            ("border-color", "#e2e8f0"),
                        ],
                    },
                ]
            )
        )
        st.dataframe(styled, hide_index=True, use_container_width=True, height=height, key=key)
    except Exception:
        st.dataframe(display_df, hide_index=True, use_container_width=True, height=height, key=key)


def render_add_settlement_form(df: pd.DataFrame) -> None:
    st.subheader("Добавить населённый пункт и вопрос")
    st.caption("Одна отправка формы добавляет одну строку: населённый пункт, вопрос и ответ. Для нескольких вопросов отправьте форму несколько раз.")

    existing_regions = [""] + sorted([x for x in df["region"].dropna().unique() if x])
    existing_districts = [""] + sorted([x for x in df["district"].dropna().unique() if x])
    existing_questions = question_catalog(df)
    question_options = ["Новый вопрос"] + [
        f"{row.question_id} · {row.question}" for row in existing_questions.itertuples()
    ]

    with st.form("add_settlement_form", clear_on_submit=False):
        c1, c2, c3 = st.columns(3)
        with c1:
            region_choice = st.selectbox("Регион", existing_regions, index=0)
            region_custom = st.text_input("Новый регион", placeholder="если его нет в списке")
            settlement_type = st.text_input("Тип населённого пункта", placeholder="село, деревня, посёлок")
        with c2:
            district_choice = st.selectbox("Район / округ", existing_districts, index=0)
            district_custom = st.text_input("Новый район / округ", placeholder="если его нет в списке")
            landscape = st.text_input("Ландшафт", placeholder="например: лесной, речной, городской")
        with c3:
            settlement = st.text_input("Населённый пункт *", placeholder="название")
            latitude = st.text_input("Широта *", placeholder="например: 56.8526")
            longitude = st.text_input("Долгота *", placeholder="например: 53.2045")

        st.markdown("#### Вопрос и ответ")
        q1, q2, q3 = st.columns([1.1, 1.2, 1.6])
        with q1:
            atlas_system = st.selectbox("Атлас", ["ДАРЯ", "ЛАРНГ", "не указан"], index=0)
            question_type = st.selectbox("Тип вопроса", ALLOWED_QUESTION_TYPES + ["не указан"], index=0)
        with q2:
            selected_question = st.selectbox("Существующий вопрос", question_options, index=0)
            question_id = st.text_input("Код нового вопроса", placeholder="например: D-0001")
        with q3:
            question = st.text_area("Формулировка вопроса *", placeholder="Введите вопрос, если выбран «Новый вопрос»", height=92)

        u1, u2, u3 = st.columns(3)
        with u1:
            unit_1 = st.text_input("Лингвистическая единица / ответ *", placeholder="можно через ;")
        with u2:
            unit_2 = st.text_input("Дополнительный ответ", placeholder="необязательно")
        with u3:
            unit_3 = st.text_input("Дополнительный ответ 2", placeholder="необязательно")

        c4, c5 = st.columns([2, 1])
        with c4:
            comment = st.text_area("Комментарий", placeholder="источник, примечание, контекст записи", height=80)
        with c5:
            source = st.text_input("Источник", placeholder="экспедиция, архив, публикация")
            year = st.text_input("Год", placeholder="например: 2026")

        submitted = st.form_submit_button("Добавить в текущую таблицу")

    if not submitted:
        return

    errors: list[str] = []
    region = (region_custom or region_choice).strip()
    district = (district_custom or district_choice).strip()
    settlement = settlement.strip()
    unit_1 = unit_1.strip()
    question_text = question.strip()

    if selected_question != "Новый вопрос" and not question_text:
        question_text = selected_question.split(" · ", 1)[1]
        if not question_id.strip():
            question_id = selected_question.split(" · ", 1)[0]

    if not region:
        errors.append("Укажите регион.")
    if not district:
        errors.append("Укажите район / округ.")
    if not settlement:
        errors.append("Укажите населённый пункт.")
    if not question_text:
        errors.append("Укажите формулировку вопроса.")
    if not unit_1:
        errors.append("Укажите хотя бы одну лингвистическую единицу / ответ.")

    try:
        lat_value = parse_float_input(latitude, "Широта")
        lon_value = parse_float_input(longitude, "Долгота")
        if not (-90 <= lat_value <= 90):
            errors.append("Широта должна быть от -90 до 90.")
        if not (-180 <= lon_value <= 180):
            errors.append("Долгота должна быть от -180 до 180.")
    except ValueError as exc:
        errors.append(str(exc))
        lat_value = None
        lon_value = None

    if errors:
        for error in errors:
            st.error(error)
        return

    record = {col: "" for col in CANONICAL_COLUMNS}
    record.update(
        {
            "region": region,
            "district": district,
            "settlement": settlement,
            "settlement_type": settlement_type.strip(),
            "latitude": lat_value,
            "longitude": lon_value,
            "landscape": landscape.strip() or "не указан",
            "atlas_system": atlas_system,
            "question_type": question_type,
            "question_id": question_id.strip() or _make_question_id(atlas_system, question_text),
            "question": question_text,
            "linguistic_unit_1": unit_1,
            "linguistic_unit_2": unit_2.strip(),
            "linguistic_unit_3": unit_3.strip(),
            "comment": comment.strip(),
            "source": source.strip() or "добавлено в приложении",
            "year": year.strip(),
        }
    )

    st.session_state.setdefault("added_records", []).append(record)
    st.success("Запись добавлена в текущую таблицу. Карта обновится автоматически.")
    st.rerun()


def render_main_page(df: pd.DataFrame, filters: dict, source_note: str) -> None:
    st.caption(f"Источник: {source_note}")

    filtered = filter_dataframe(
        df,
        regions=filters["regions"],
        districts=filters["districts"],
        question=filters["selected_question"],
        unit_query=filters["unit_query"],
        text_query=filters["text_query"],
    )

    st.subheader("Карта")
    st.markdown('<div class="map-caption">Точки можно наводить мышью для просмотра данных. Ареалы не подсвечиваются при наведении.</div>', unsafe_allow_html=True)

    left, right = st.columns([3.15, 1.05], gap="large")
    with left:
        deck, points_df, areals = make_deck(
            filtered,
            selected_question=filters["selected_question"],
            color_mode=filters["color_mode"],
            show_areals=filters["show_areals"],
            show_isoglosses=filters["show_isoglosses"],
            show_labels=filters["show_labels"],
            geojson_url="",
            height=620,
        )
        if deck is None:
            st.warning("Нет точек с координатами для выбранных фильтров.")
        else:
            st.pydeck_chart(deck, use_container_width=True)
    with right:
        render_legend(points_df if "points_df" in locals() else pd.DataFrame(), areals if "areals" in locals() else [])

    st.divider()
    render_add_settlement_form(df)

    st.divider()
    st.subheader("Таблица данных")
    table_df = add_unit_display(filtered)
    table_cols = [
        "region",
        "district",
        "settlement",
        "settlement_type",
        "latitude",
        "longitude",
        "landscape",
        "atlas_system",
        "question_type",
        "question_id",
        "question",
        "unit_display",
        "comment",
        "source",
        "year",
    ]
    available_cols = [col for col in table_cols if col in table_df.columns]
    render_light_dataframe(table_df[available_cols], key="main_light_data_table", height=460)

    col_a, col_b = st.columns(2)
    with col_a:
        st.download_button(
            "Скачать текущую таблицу CSV",
            data=to_download_csv(df),
            file_name="dialekt_udmurtii_current.csv",
            mime="text/csv",
        )
    with col_b:
        if st.session_state.get("added_records"):
            if st.button("Очистить добавленные в этой сессии записи"):
                st.session_state["added_records"] = []
                st.rerun()


def main() -> None:
    page_setup()
    source_df, source_note, _editor_url = load_data_sidebar()
    df = get_working_dataframe(source_df)

    filters = sidebar_filters(df)
    render_header(df)
    render_main_page(df, filters, source_note)


if __name__ == "__main__":
    main()
